from langchain_core.runnables import RunnableLambda
from langchain_core.prompts import ChatPromptTemplate

class FakeLLM:
    def __call__(self, prompt):
        # Simulates LangChain LLM returning None when streaming aborted
        return {'output': 'summary', 'llm_output': None}

def extract_tokens(response):
    llm_output = response['llm_output']
    return llm_output.get('token_usage', {})

def build_chain():
    llm = FakeLLM()
    prompt = ChatPromptTemplate.from_messages([('user', '{query}')])
    chain = RunnableLambda(lambda x: llm(prompt.format(**x)))
    chain = chain | RunnableLambda(extract_tokens)
    return chain

if __name__ == '__main__':
    chain = build_chain()
    result = chain.invoke({'query': 'summarize'})
    print(result)
